requestBody.query:
{
      siteMessage(displayLocation:"top", url:"/nx/search/jobs/") {
        title
        templateUid: templateId
        content
        dismissible
        displayLocation
        severity
      }
    }

query GetSpellCheck($query: String!) {
  search {
    universalSearchNuxt {
      freelancerSpellCheckSuggestionV1(query: $query) {
        suggestion
        isEqualToOriginalQuery
      }
    }
  }
}

query GetUserTopRatedStatus {
  user {
    talentProfile {
      profileAggregates {
        topRatedStatus
      }
    }
  }
}

query GetAutoSuggestions($request: UserUniversalSearchSuggestionInput!) {
  allSuggestions(input: $request) {
    snippet
    suggestions {
      suggestion
    }
    peopleFirstNameSuggestions {
      suggestion
    }
    peopleSuggestions {
      label: fullName
      profile {
        identity {
          id
        }
      }
    }
    recentUserSuggestions {
      suggestion
      suggestionId
    }
  }
}

fragment JobPubOpeningInfoFragment on Job {
    ciphertext
    id
    type
    access
    title
    hideBudget
    createdOn
    notSureProjectDuration
    notSureFreelancersToHire
    notSureExperienceLevel
    notSureLocationPreference
    premium
  }
  fragment JobPubOpeningSegmentationDataFragment on JobSegmentation {
    customValue
    label
    name
    sortOrder
    type
    value
    skill {
      description
      externalLink
      prettyName
      skill
      id
    }
  }
  fragment JobPubOpeningSandDataFragment on SandsData {
    occupation {
      freeText
      ontologyId
      prefLabel
      id
      uid: id
    }
    ontologySkills {
      groupId
      id
      freeText
      prefLabel
      groupPrefLabel
      relevance
    }
    additionalSkills {
      groupId
      id
      freeText
      prefLabel
      relevance
    }
  }
  fragment JobPubOpeningFragment on JobPubOpeningInfo {
    status
    postedOn
    publishTime
    sourcingTime
    startDate
    deliveryDate
    workload
    contractorTier
    description
    info {
      ...JobPubOpeningInfoFragment
    }
    segmentationData {
      ...JobPubOpeningSegmentationDataFragment
    }
    sandsData {
      ...JobPubOpeningSandDataFragment
    }
    category {
      name
      urlSlug
    }
    categoryGroup {
      name
      urlSlug
    }
    budget {
      amount
      currencyCode
    }
    annotations {
      customFields
      tags
    }
    engagementDuration {
      label
      weeks
    }
    extendedBudgetInfo {
      hourlyBudgetMin
      hourlyBudgetMax
      hourlyBudgetType
    }
    attachments @include(if: $isLoggedIn) {
      fileName
      length
      uri
    }
    clientActivity {
      lastBuyerActivity
      totalApplicants
      totalHired
      totalInvitedToInterview
      unansweredInvites
      invitationsSent
      numberOfPositionsToHire
    }
    deliverables
    deadline
    tools {
      name
    }
  }
  fragment JobQualificationsFragment on JobQualifications {
    countries
    earnings
    groupRecno
    languages
    localDescription
    localFlexibilityDescription
    localMarket
    minJobSuccessScore
    minOdeskHours
    onSiteType
    prefEnglishSkill
    regions
    risingTalent
    shouldHavePortfolio
    states
    tests
    timezones
    type
    locationCheckRequired
    group {
      groupId
      groupLogo
      groupName
    }
    location {
      city
      country
      countryTimezone
      offsetFromUtcMillis
      state
      worldRegion
    }
    locations {
      id
      type
    }
    minHoursWeek @skip(if: $isLoggedIn)
  }
  fragment JobAuthDetailsOpeningFragment on JobAuthOpeningInfo {
    job {
      ...JobPubOpeningFragment
    }
    qualifications {
      ...JobQualificationsFragment
    }
    questions {
      question
      position
    }
  }
  fragment JobPubBuyerInfoFragment on JobPubBuyerInfo {
    location {
      offsetFromUtcMillis
      countryTimezone
      city
      country
    }
    stats {
      totalAssignments
      activeAssignmentsCount
      hoursCount
      feedbackCount
      score
      totalJobsWithHires
      totalCharges {
        amount
      }
    }
    company {
      name @include(if: $isLoggedIn)
      companyId @include(if: $isLoggedIn)
      isEDCReplicated
      contractDate
      profile {
        industry
        size
      }
    }
    jobs {
      openCount
      postedCount @include(if: $isLoggedIn)
      openJobs {
        id
        uid: id
        isPtcPrivate
        ciphertext
        title
        type
      }
    }
    avgHourlyJobsRate @include(if: $isLoggedIn) {
      amount
    }
  }
  fragment JobAuthDetailsBuyerWorkHistoryFragment on BuyerWorkHistoryItem {
    isPtcJob
    status
    isEDCReplicated
    isPtcPrivate
    startDate
    endDate
    totalCharge
    totalHours
    jobInfo {
      title
      id
      uid: id
      access
      type
      ciphertext
    }
    contractorInfo {
      contractorName
      accessType
      ciphertext
    }
    rate {
      amount
    }
    feedback {
      feedbackSuppressed
      score
      comment
    }
    feedbackToClient {
      feedbackSuppressed
      score
      comment
    }
  }
  fragment JobAuthDetailsBuyerFragment on JobAuthBuyerInfo {
    enterprise
    isPaymentMethodVerified
    info {
      ...JobPubBuyerInfoFragment
    }
    workHistory {
      ...JobAuthDetailsBuyerWorkHistoryFragment
    }
  }
  fragment JobAuthDetailsCurrentUserInfoFragment on JobCurrentUserInfo {
    owner
    freelancerInfo {
      profileState
      applied
      devProfileCiphertext
      hired
      application {
        vjApplicationId
      }
      pendingInvite {
        inviteId
      }
      contract {
        contractId
        status
      }
      hourlyRate {
        amount
      }
      qualificationsMatches {
        matches {
          clientPreferred
          clientPreferredLabel
          freelancerValue
          freelancerValueLabel
          qualification
          qualified
        }
      }
    }
  }
  query JobAuthDetailsQuery(
    $id: ID!
    $isFreelancerOrAgency: Boolean!
    $isLoggedIn: Boolean!
  ) {
    jobAuthDetails(id: $id) {
      hiredApplicantNames
      opening {
        ...JobAuthDetailsOpeningFragment
      }
      buyer {
        ...JobAuthDetailsBuyerFragment
      }
      currentUserInfo {
        ...JobAuthDetailsCurrentUserInfoFragment
      }
      similarJobs {
        id
        uid: id
        ciphertext
        title
        snippet
      }
      workLocation {
        onSiteCity
        onSiteCountry
        onSiteReason
        onSiteReasonFlexible
        onSiteState
        onSiteType
      }
      phoneVerificationStatus {
        status
      }
      applicantsBidsStats {
        avgRateBid {
          amount
          currencyCode
        }
        minRateBid {
          amount
          currencyCode
        }
        maxRateBid {
          amount
          currencyCode
        }
      }
      specializedProfileOccupationId @include(if: $isFreelancerOrAgency)
      applicationContext @include(if: $isFreelancerOrAgency) {
        freelancerAllowed
        clientAllowed
      }
    }
  }

query connectsDataForFreelancer($jobId: ID!) {
  pricingJobPost: jobConnectsPriceFreelancer(jobId: $jobId) {
    price
    context
    auctionPrice
  }
  connectsSummary: jobFreelancerConnectsSummary {
    connectsBalance
  }
  jobFeatureInCurrentSubscription(feature: VIEW_COMPETITOR_BIDS) {
    featureInCurrentSubscription
  }
  chooseConnectsModalStatus {
    isExplainerModalShown
  }
}

query ($jobPostingId: ID!) {
  aiInterviewer {
    jobStatus(jobPostingId: $jobPostingId) {
      jobPostingId
      aiInterviewerEnabled
    }
  }
}

query GetPersonSavedJobs($jobIds: [ID], $followed: Boolean) {
  getPersonSavedJobs(jobIds: $jobIds, followed: $followed) {
    personSavedJobs {
      job {
        id
      }
    }
  }
}

mutation SavePersonJob($requestBody: PersonSaveJobInput!) {
  savePersonJob(input: $requestBody) {
    followed
    job {
      id
    }
  }
}

query GetLLMSuggestedBid($jobId: ID!) {
  llmSuggestedBid(
    jobPostId: $jobId
  ) {
    threadId
    header
    lines
    fitScore
  }
}

